import type { Page } from '@playwright/test';
import { NousinfosystemsHomePageLocators } from '@locators/NousinfosystemsHomePage.locators';

/**
 * Page Object — NousinfosystemsHome
 * Methods only — no assertions, no test logic.
 * Instantiate once per test; pass `page` from the Playwright fixture.
 */
export class NousinfosystemsHomePage {
  constructor(private readonly page: Page) {}

  /** Click the primary Contact Us navigation link */
  async clickContactUs(): Promise<void> {
    await NousinfosystemsHomePageLocators.contactUsLink(this.page).click();
  }

  /** Click the About Us navigation link */
  async clickAboutUs(): Promise<void> {
    await NousinfosystemsHomePageLocators.aboutUsLink(this.page).click();
  }

  /** Click the Get Started CTA button on the hero section */
  async clickGetStarted(): Promise<void> {
    await NousinfosystemsHomePageLocators.getStartedButton(this.page).click();
  }

  /** Returns true when the H1 hero heading is visible on screen */
  async isHeroHeadingVisible(): Promise<boolean> {
    return NousinfosystemsHomePageLocators.heroHeading(this.page).isVisible();
  }

  /** Returns the text content of the H1 hero heading */
  async getHeroHeadingText(): Promise<string> {
    return NousinfosystemsHomePageLocators.heroHeading(this.page).innerText();
  }

  /** Returns true when the top navigation bar is visible */
  async isNavigationVisible(): Promise<boolean> {
    return NousinfosystemsHomePageLocators.navigationMenu(this.page).isVisible();
  }
}

import type { Page } from '@playwright/test';
import { NousinfosystemsHomePage } from '@pages/NousinfosystemsHomePage';
import { navigateTo, waitForNetworkIdle } from '@actions/generic/browser.actions';
import { verifyText, verifyUrl } from '@actions/generic/assert.actions';
import type { TestDataRow } from '@fixtures/excel-reader';

/**
 * Navigate to the Nousinfosystems home page using the baseUrl from test data.
 * Waits for the network to settle before returning.
 */
export async function navigateToHomePage(page: Page, _data: TestDataRow): Promise<void> {
  await navigateTo(page, _data.baseUrl || 'https://www.nousinfosystems.com/');
  await waitForNetworkIdle(page);
}

/**
 * Verify the home page has loaded correctly:
 * - Page contains 'Nousinfosystems' text
 * - Hero heading element is visible
 * - Navigation bar is visible
 */
export async function verifyNousinfosystemshome(page: Page, _data: TestDataRow): Promise<void> {
  const pg = new NousinfosystemsHomePage(page);
  await verifyText(page, 'Nousinfosystems');
  const headingVisible = await pg.isHeroHeadingVisible();
  if (!headingVisible) throw new Error('Hero heading not visible on home page');
  const navVisible = await pg.isNavigationVisible();
  if (!navVisible) throw new Error('Navigation menu not visible on home page');
}

/**
 * Click the Contact Us link and verify navigation to the contact page.
 */
export async function clickContactUsAndVerify(page: Page, _data: TestDataRow): Promise<void> {
  const pg = new NousinfosystemsHomePage(page);
  await pg.clickContactUs();
  await waitForNetworkIdle(page);
  await verifyUrl(page, 'contact');
}

import { test } from '@playwright/test';
import {
  navigateToHomePage,
  verifyNousinfosystemshome,
} from '@actions/business/nousinfosystemshome.actions';
import { getTestData } from '@fixtures/excel-reader';
import { prepareSite } from '@helpers/universal';

test.describe('TC001 — Verify Home Page', () => {
  test('verify nousinfosystems home page loads and hero heading is visible', async ({ page }) => {
    const data = getTestData('TC001');
    await navigateToHomePage(page, data);
    await prepareSite(page);
    await verifyNousinfosystemshome(page, data);
  });
});

